#include <bits/stdc++.h>
using namespace std;

typedef long long ll;

const int N=1e5+5;

struct Node{
    ll sum,len;
    int mx;
};

bool operator<(Node x,Node y){
    if(x.sum==y.sum)
        return x.mx>y.mx;
    return x.sum>y.sum;
}

int n,k;
priority_queue<Node> q;

int main(){
    scanf("%d%d",&n,&k);
    for(int i=1;i<=n;i++){
        ll w;
        scanf("%lld",&w);
        q.push({w,0,0});
    }
    while((n-1)%(k-1))
        n++,q.push({0,0,0});
    while(q.size()-1){
        Node tmp={0,0,0};
        for(int i=1;i<=k && !q.empty();i++){
            Node a=q.top();
            q.pop();
            tmp={tmp.sum+a.sum,tmp.len+a.sum+a.len,max(tmp.mx,a.mx+1)};
        }
        q.push(tmp);
    }
    printf("%lld\n%d",q.top().len,q.top().mx);
    return 0;
}
